              </div>
              <div className="text-gray-400">
                {language === 'en' 
                  ? '• No tax applies when tax-free account is selected' 
                  : '• 비과세 계좌 선택 시 세금이 적용되지 않습니다'}
              </div>
            </div>

            {/* Dividend Yield */}
            <div>
              <Label className="flex items-center">
                {t.calculator.dividendYield}
                <Tooltip>
