                    <button type="button" className="ml-1">
                      <Info className="h-4 w-4 text-gray-400" />
                    </button>
                  </TooltipTrigger>
                  <TooltipContent>
                    {language === 'en' ? 'Annual dividend yield relative to current stock price' : '현재 주가 대비 연간 배당 수익률'}
