                  </TooltipTrigger>
                  <TooltipContent>
                    {language === 'en' ? 'Annual dividend growth rate' : '매년 배당금이 증가하는 비율'}
                  </TooltipContent>
                </Tooltip>
              </Label>
              <div className="relative">
                <Input
                  type="number"
                  step="0.1"
                  placeholder={t.calculator.placeholders.growthPercent}
                  className="pr-8"
                  {...form.register("dividendGrowthRate", { valueAsNumber: true })}
                  onChange={(e) => {
                    form.setValue("dividendGrowthRate", parseFloat(e.target.value) || 0);
                    setSelectedPreset(null); // Reset preset on manual input
                  }}
                />
                <span className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-500">
                  %
                </span>
              </div>
              {form.formState.errors.dividendGrowthRate && (
                <p className="text-sm text-red-600">{form.formState.errors.dividendGrowthRate.message}</p>
              )}
            </div>

            {/* DRIP Toggle */}
            <div className="flex items-center space-x-2">
              <Switch
                id="drip"
                {...form.register("dripEnabled")}
                checked={form.watch("dripEnabled")}
                onCheckedChange={(checked) => form.setValue("dripEnabled", checked)}
              />
              <Label htmlFor="drip" className="flex items-center">
                {t.calculator.dripEnabled}
                <Tooltip>
                  <TooltipTrigger asChild>
                    <button type="button" className="ml-1">
                      <Info className="h-4 w-4 text-gray-400" />
                    </button>
                  </TooltipTrigger>
                  <TooltipContent>
                    {language === 'en' ? 'Automatically reinvest dividends instead of receiving cash' : '배당금을 현금으로 받지 않고 자동으로 재투자'}
                  </TooltipContent>
                </Tooltip>
              </Label>
            </div>



            <Button 
              type="submit" 
              className="w-full" 
              disabled={calculateMutation.isPending}
            >
              <Calculator className="mr-2 h-4 w-4" />
              {calculateMutation.isPending 
                ? (language === 'en' ? 'Calculating...' : '계산 중...') 
                : t.calculator.calculateButton}
            </Button>
          </form>
        </CardContent>
      </Card>

      {/* Quick Presets */}
      <Card>
        <CardHeader>
          <CardTitle className="text-md font-semibold text-gray-900">
            {language === 'en' ? 'Quick Presets' : '빠른 설정'}
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-2 gap-3">
            {Object.entries(presets).map(([key, preset]) => (
              <Button
                key={key}
                variant={selectedPreset === key ? "default" : "outline"}
                className="p-3 h-auto text-left justify-start"
                onClick={() => loadPreset(key as keyof typeof presets)}
              >
                <div>
                  <div className="text-sm font-medium">{preset.label}</div>
                  <div className="text-xs text-gray-500">{preset.description}</div>
                </div>
              </Button>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/components/comparison-form.ts.content:
import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { BarChart3 } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { useMutation } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import type { ComparisonResults } from "@/pages/comparison";

const comparisonSchema = z.object({
  stockA: z.string().min(1, "종목 A 티커를 입력해주세요"),
  stockB: z.string().min(1, "종목 B 티커를 입력해주세요"),
  initialInvestment: z.number().min(0, "초기 투자금은 0 이상이어야 합니다"),
  monthlyInvestment: z.number().min(0, "월 투자금은 0 이상이어야 합니다"),
  investmentPeriod: z.number().min(1, "투자 기간은 최소 1년이어야 합니다").max(50, "투자 기간은 최대 50년입니다"),
});

type ComparisonFormData = z.infer<typeof comparisonSchema>;

interface ComparisonFormProps {
  onCompare: (results: ComparisonResults) => void;
}

export default function ComparisonForm({ onCompare }: ComparisonFormProps) {
  const { toast } = useToast();
  const [selectedPeriod, setSelectedPeriod] = useState(10);

  const form = useForm<ComparisonFormData>({
    resolver: zodResolver(comparisonSchema),
    defaultValues: {
      stockA: "",
      stockB: "",
      initialInvestment: 10000,
      monthlyInvestment: 500,
      investmentPeriod: 10,
    },
  });

  const compareMutation = useMutation({
    mutationFn: async (data: ComparisonFormData) => {
      const response = await apiRequest("POST", "/api/compare", data);
      return response.json();
    },
    onSuccess: (results: ComparisonResults) => {
      onCompare(results);
      toast({
        title: "비교 완료!",
        description: "종목 비교 분석이 완료되었습니다.",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "비교 오류",
        description: error.message || "비교 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data: ComparisonFormData) => {
    compareMutation.mutate(data);
  };

  const setPeriod = (years: number) => {
    setSelectedPeriod(years);
    form.setValue("investmentPeriod", years);
  };

  const popularComparisons = [
    { stockA: "SCHD", stockB: "VTI", label: "SCHD vs VTI", description: "배당 성장 vs 전체 시장" },
    { stockA: "SCHD", stockB: "SPY", label: "SCHD vs SPY", description: "배당 성장 vs S&P 500" },
    { stockA: "SCHD", stockB: "QQQ", label: "SCHD vs QQQ", description: "배당 성장 vs 나스닥" },
  ];

  const loadComparison = (stockA: string, stockB: string) => {
    form.setValue("stockA", stockA);
    form.setValue("stockB", stockB);
  };

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="text-lg font-semibold text-gray-900">
            종목 비교 설정
          </CardTitle>
        </CardHeader>
        <CardContent>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
            {/* Stock A */}
            <div>
              <Label>종목 A 티커</Label>
              <Input
                type="text"
                placeholder="SCHD"
                className="uppercase"
                {...form.register("stockA")}
              />
              {form.formState.errors.stockA && (
                <p className="text-sm text-red-600">{form.formState.errors.stockA.message}</p>
              )}
            </div>

            {/* Stock B */}
            <div>
              <Label>종목 B 티커</Label>
              <Input
                type="text"
                placeholder="VTI"
                className="uppercase"
                {...form.register("stockB")}
              />
              {form.formState.errors.stockB && (
                <p className="text-sm text-red-600">{form.formState.errors.stockB.message}</p>
              )}
            </div>

            {/* Investment Period */}
            <div>
              <Label className="mb-2 block">투자 기간</Label>
              <div className="grid grid-cols-2 gap-2">
                {[5, 10, 15, 30].map((years) => (
                  <Button
                    key={years}
                    type="button"
                    variant={selectedPeriod === years ? "default" : "outline"}
                    className="text-sm"
                    onClick={() => setPeriod(years)}
                  >
                    {years}년
                  </Button>
                ))}
              </div>
            </div>

            {/* Initial Investment */}
            <div>
              <Label>초기 투자금</Label>
              <div className="relative">
                <span className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-500">
                  $
                </span>
                <Input
                  type="number"
                  placeholder="10,000"
                  className="pl-8"
                  {...form.register("initialInvestment", { valueAsNumber: true })}
                />
              </div>
              {form.formState.errors.initialInvestment && (
                <p className="text-sm text-red-600">{form.formState.errors.initialInvestment.message}</p>
              )}
            </div>

            {/* Monthly Investment */}
            <div>
              <Label>월 투자금</Label>
              <div className="relative">
                <span className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-500">
                  $
                </span>
                <Input
                  type="number"
                  placeholder="500"
                  className="pl-8"
                  {...form.register("monthlyInvestment", { valueAsNumber: true })}
                />
              </div>
              {form.formState.errors.monthlyInvestment && (
                <p className="text-sm text-red-600">{form.formState.errors.monthlyInvestment.message}</p>
              )}
            </div>

            <Button 
              type="submit" 
              className="w-full bg-green-600 hover:bg-green-700" 
              disabled={compareMutation.isPending}
            >
              <BarChart3 className="mr-2 h-4 w-4" />
              {compareMutation.isPending ? "비교 중..." : "종목 비교하기"}
            </Button>
          </form>
        </CardContent>
      </Card>

      {/* Popular Comparisons */}
      <Card>
        <CardHeader>
          <CardTitle className="text-md font-semibold text-gray-900">인기 비교</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-2">
            {popularComparisons.map((comparison, index) => (
              <Button
                key={index}
                variant="outline"
                className="w-full p-3 h-auto text-left justify-start"
                onClick={() => loadComparison(comparison.stockA, comparison.stockB)}
              >
                <div>
                  <div className="text-sm font-medium">{comparison.label}</div>
                  <div className="text-xs text-gray-500">{comparison.description}</div>
                </div>
              </Button>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/components/navigation.tsx.content:
import { Link, useLocation } from "wouter";
import { Calculator, BarChart3, Menu, Globe, CalendarDays, Target } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Sheet, SheetContent, SheetTrigger } from "@/components/ui/sheet";
import { 
  DropdownMenu, 
  DropdownMenuContent, 
  DropdownMenuItem, 
  DropdownMenuTrigger 
} from "@/components/ui/dropdown-menu";

export default function Navigation() {
  const [location] = useLocation();

  const getCurrentLanguage = () => {
    if (location.startsWith('/en')) return 'EN';
    if (location.startsWith('/kr')) return 'KR';
    return 'KR'; // default
  };

  const getLanguageRedirect = (newLang: string) => {
    if (newLang === 'en') return '/en';
    if (newLang === 'kr') return '/kr';
    return '/';
  };

  const navItems: Array<{
    href: string;
    label: string;
    icon: any;
    isActive: boolean;
  }> = [
    {
      href: getCurrentLanguage() === 'EN' ? "/en" : "/kr",
      label: getCurrentLanguage() === 'EN' ? "Dividend Calculator" : "배당 재투자 계산기",
      icon: Calculator,
      isActive: location === "/" || location === "/kr" || location === "/en" || location === "/calculator",
    },
    {
      href: getCurrentLanguage() === 'EN' ? "/en/fire" : "/fire",
      label: getCurrentLanguage() === 'EN' ? "FIRE Calculator" : "FIRE 계산기",
      icon: Target,
      isActive: location === "/fire" || location === "/kr/fire" || location === "/en/fire",
    },
    // {
    //   href: "/comparison",
    //   label: "종목 비교",
    //   icon: BarChart3,
    //   isActive: location === "/comparison",
    // },
  ];

  const NavContent = () => (
    <>
      {navItems.map((item) => {
        const Icon = item.icon;
        return (
          <Link key={item.href} href={item.href}>
            <Button
              variant={item.isActive ? "default" : "ghost"}
              className="w-full justify-start"
            >
              <Icon className="mr-2 h-4 w-4" />
              {item.label}
            </Button>
          </Link>
        );
      })}
    </>
  );

  return (
    <nav className="bg-white border-b border-gray-200 sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          <div className="flex items-center">
            <Link href={getCurrentLanguage() === 'EN' ? '/en' : '/kr'}>
              <h1 className="text-xl font-bold text-gray-900 flex items-center">
                <BarChart3 className="mr-2 h-6 w-6 text-primary" />
                {getCurrentLanguage() === 'EN' ? 'Dividend Reinvestment Calculator' : '배당 재투자 계산기'}
              </h1>
            </Link>
          </div>

          <div className="flex items-center space-x-4">
            {/* Language Selector */}
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="outline" size="sm">
                  <Globe className="mr-2 h-4 w-4" />
                  {getCurrentLanguage()}
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end">
                <DropdownMenuItem asChild>
                  <Link href={getLanguageRedirect('kr')}>
                    🇰🇷 한국어
                  </Link>
                </DropdownMenuItem>
                <DropdownMenuItem asChild>
                  <Link href={getLanguageRedirect('en')}>
                    🇺🇸 English
                  </Link>
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>

          {/* Desktop Navigation - Hidden when no nav items */}
          {navItems.length > 0 && (
            <div className="hidden md:flex items-center space-x-4">
              <NavContent />
            </div>
          )}

          {/* Mobile Navigation - Hidden when no nav items */}
          {navItems.length > 0 && (
            <div className="md:hidden">
              <Sheet>
                <SheetTrigger asChild>
                  <Button variant="ghost" size="icon">
                    <Menu className="h-5 w-5" />
                  </Button>
                </SheetTrigger>
                <SheetContent side="right" className="w-64">
                  <div className="flex flex-col space-y-4 mt-4">
                    <NavContent />
                  </div>
                </SheetContent>
              </Sheet>
            </div>
          )}
        </div>
      </div>
    </nav>
  );
}

client/src/components/results-charts.tsx.content:
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { LineChart, Line, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from "recharts";
import { getCurrentLanguage, getTranslation } from "@/lib/i18n";
import type { CalculationResults } from "@/pages/calculator";

interface ResultsChartsProps {
  results: CalculationResults;
  comparisonResults?: CalculationResults;
  formatCurrency: (amount: number) => string;
  stockATicker?: string;
  stockBTicker?: string;
}

export default function ResultsCharts({ 
  results, 
  comparisonResults, 
  formatCurrency,
  stockATicker = "종목 A",
  stockBTicker = "종목 B"
}: ResultsChartsProps) {
  const language = getCurrentLanguage();
  const t = getTranslation(language);
  const isComparison = !!comparisonResults;

  // Prepare data for charts
  const chartData = results.yearlyData.map((item, index) => ({
    year: language === 'en' ? `Year ${item.year}` : `${item.year}년`,
    totalAssets: item.totalAssets,
    dividends: item.annualDividends,
    cumulativeDividends: item.cumulativeDividends,
    ...(comparisonResults && {
      totalAssetsB: comparisonResults.yearlyData[index]?.totalAssets || 0,
      dividendsB: comparisonResults.yearlyData[index]?.annualDividends || 0,
      cumulativeDividendsB: comparisonResults.yearlyData[index]?.cumulativeDividends || 0,
    }),
  }));

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-white p-3 border border-gray-200 rounded-lg shadow-sm">
          <p className="font-medium">{label}</p>
          {payload.map((entry: any, index: number) => (
            <p key={index} style={{ color: entry.color }}>
              {entry.name}: {formatCurrency(entry.value)}
            </p>
          ))}
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-6">
      {/* Asset Growth Chart */}
      <Card>
        <CardHeader>
          <CardTitle>
            {isComparison 
              ? (language === 'en' ? "Asset Growth Comparison" : "자산 성장 비교")
              : (language === 'en' ? "Asset Growth Trend" : "자산 성장 추이")
            }
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={chartData} margin={{ top: 20, right: 30, left: 40, bottom: 20 }}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="year" tick={{ fontSize: 11 }} />
                <YAxis tickFormatter={(value) => formatCurrency(value)} tick={{ fontSize: 11 }} />
                <Tooltip content={<CustomTooltip />} />
                {isComparison && <Legend />}
                <Line
                  type="monotone"
                  dataKey="totalAssets"
                  stroke="hsl(207, 90%, 54%)"
                  strokeWidth={2}
                  name={isComparison ? stockATicker : (language === 'en' ? "Total Assets" : "총 자산")}
                  dot={{ fill: "hsl(207, 90%, 54%)", strokeWidth: 2 }}
                />
                {comparisonResults && (
                  <Line
                    type="monotone"
                    dataKey="totalAssetsB"
                    stroke="hsl(142, 76%, 47%)"
                    strokeWidth={2}
                    name={stockBTicker}
                    dot={{ fill: "hsl(142, 76%, 47%)", strokeWidth: 2 }}
                  />
                )}
              </LineChart>
            </ResponsiveContainer>
          </div>
        </CardContent>
      </Card>

      {/* Dividend Growth Chart */}
      <Card>
        <CardHeader>
          <CardTitle>
            {isComparison 
              ? (language === 'en' ? "Dividend Comparison" : "배당금 비교")
              : (language === 'en' ? "Dividend Growth Trend" : "배당금 성장 추이")
            }
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} margin={{ top: 20, right: 30, left: 40, bottom: 20 }}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="year" tick={{ fontSize: 11 }} />
                <YAxis tickFormatter={(value) => formatCurrency(value)} tick={{ fontSize: 11 }} />
                <Tooltip content={<CustomTooltip />} />
                {isComparison && <Legend />}
                <Bar
                  dataKey="dividends"
                  fill="hsl(142, 76%, 47%)"
                  name={isComparison 
                    ? `${stockATicker} ${language === 'en' ? 'Annual Dividend' : '연초 배당금'}` 
                    : (language === 'en' ? "Annual Dividend" : "연초 배당금")
                  }
                  radius={[4, 4, 0, 0]}
                />
                {comparisonResults && (
                  <Bar
                    dataKey="dividendsB"
                    fill="hsl(25, 95%, 53%)"
                    name={`${stockBTicker} ${language === 'en' ? 'Annual Dividend' : '연초 배당금'}`}
                    radius={[4, 4, 0, 0]}
                  />
                )}
              </BarChart>
            </ResponsiveContainer>
          </div>
        </CardContent>
      </Card>

      {/* Cumulative Dividends Chart */}
      {!isComparison && (
        <Card>
          <CardHeader>
            <CardTitle>
              {language === 'en' ? "Cumulative Dividends Trend" : "누적 배당금 추이"}
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-80">
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={chartData} margin={{ top: 20, right: 30, left: 40, bottom: 20 }}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="year" tick={{ fontSize: 11 }} />
                  <YAxis tickFormatter={(value) => formatCurrency(value)} tick={{ fontSize: 11 }} />
