                        <Line 
                          type="monotone" 
                          dataKey="assets" 
                          stroke="#2563eb" 
                          strokeWidth={2}
                          name="자산"
                          dot={false}
                        />
                        <ReferenceLine 
                          x={results.fireYear} 
                          stroke="#dc2626" 
                          strokeDasharray="5 5"
                          label={{ value: "FIRE", position: "top" }}
                        />
